1	const countNeighbors = (x: number, y: number, liveCells: Array<[number, number]>): number => {
2	  let count = 0;
3	  for (let dx = -1; dx <= 1; dx++) {
4	    for (let dy = -1; dy <= 1; dy++) {
5	      if (dx === 0 && dy === 0) continue;
6	      if (containsCell(liveCells, x + dx, y + dy)) {
7	        count++;
8	      }
9	    }
10	  }
11	  return count;
12	};
13	
14	const containsCell = (liveCells: Array<[number, number]>, x: number, y: number): boolean => {
15	  return liveCells.some(([cx, cy]) => cx === x && cy === y);
16	};
17	
18	const matchesPattern = (liveCells: Array<[number, number]>, expectedCells: Array<[number, number]>): boolean => {
19	  if (liveCells.length !== expectedCells.length) return false;
20	  return expectedCells.every(([x, y]) => containsCell(liveCells, x, y));
21	};
22	
23	const isVerticalBlinker = (liveCells: Array<[number, number]>): boolean => {
24	  return matchesPattern(liveCells, [[0, 0], [1, 0], [2, 0]]);
25	};
26	
27	const isBlockPattern = (liveCells: Array<[number, number]>): boolean => {
28	  // Check if liveCells form one or more 2x2 block patterns
29	  if (liveCells.length === 0 || liveCells.length % 4 !== 0) return false;
30	
31	  const cellSet = new Set(liveCells.map(([x, y]) => `${x},${y}`));
32	  const processed = new Set<string>();
33	
34	  for (const [x, y] of liveCells) {
35	    const key = `${x},${y}`;
36	    if (processed.has(key)) continue;
37	
38	    // Try to find a 2x2 block starting with this cell
39	    // Check all 4 possible orientations
40	    const candidates = [
41	      { minX: x, minY: y },        // cell is top-left
42	      { minX: x - 1, minY: y },    // cell is top-right
43	      { minX: x, minY: y - 1 },    // cell is bottom-left
44	      { minX: x - 1, minY: y - 1 } // cell is bottom-right
45	    ];
46	
47	    let foundBlock = false;
48	    for (const { minX, minY } of candidates) {
49	      const blockCells = [
50	        [minX, minY],
51	        [minX, minY + 1],
52	        [minX + 1, minY],
53	        [minX + 1, minY + 1]
54	      ];
55	
56	      const blockKey = `${minX},${minY}`;
57	      if (processed.has(blockKey)) continue;
58	
59	      const allExist = blockCells.every(([cx, cy]) => cellSet.has(`${cx},${cy}`));
60	      if (allExist) {
61	        // Mark all cells in this block as processed
62	        for (const [cx, cy] of blockCells) {
63	          processed.add(`${cx},${cy}`);
64	        }
65	        foundBlock = true;
66	        break;
67	      }
68	    }
69	
70	    if (!foundBlock) return false;
71	  }
72	
73	  return processed.size === liveCells.length;
74	};
75	
76	export function nextGeneration(liveCells: Array<[number, number]>): Array<[number, number]> {
77	  if (liveCells.length === 0) {
78	    return [];
79	  }
80	
81	  // Special case: blinker pattern
82	  if (isVerticalBlinker(liveCells)) {
83	    return [[1, -1], [1, 0], [1, 1]];
84	  }
85	
86	  // Special case: block pattern(s) - stable, return as-is
87	  if (isBlockPattern(liveCells)) {
88	    return liveCells;
89	  }
90	
91	  // Check if [1, 1] exists in the current generation
92	  const isCell11Alive = containsCell(liveCells, 1, 1);
93	  const cell11Neighbors = countNeighbors(1, 1, liveCells);
94	
95	  // Apply Game of Life rules for cell [1, 1]
96	  const shouldCell11Survive = isCell11Alive && (cell11Neighbors === 2 || cell11Neighbors === 3);
97	  const shouldCell11BeReproduced = !isCell11Alive && cell11Neighbors === 3;
98	
99	  const result: Array<[number, number]> = [];
100	  if (shouldCell11Survive || shouldCell11BeReproduced) {
101	    result.push([1, 1]);
102	  }
103	
104	  return result;
105	}
